CREATE OR REPLACE VIEW view_tge_dep_coll_loan (loan_contract_no, seq_no, operate_date, item_type, principal_amount, interest_amount, principal_balance, sign_flag, item_type_desc, value_amount) AS SELECT sc_lon_m_loan_card_detail.loan_contract_no,
sc_lon_m_loan_card_detail.period as seq_no,   
sc_lon_m_loan_card_detail.loan_payment_date as operate_date,   
sc_lon_m_loan_card_detail.item_type_code as item_type,   
sc_lon_m_loan_card_detail.payment_amount as principal_amount,   
sc_lon_m_loan_card_detail.interest_amout as interest_amount,   
sc_lon_m_loan_card_detail.principal_balance as principal_balance,   

(-1) * sc_lon_m_ucf_loan_card_item.sign_status as sign_flag,   
sc_lon_m_ucf_loan_card_item.item_type_description as item_type_desc ,

0 AS value_amount

FROM sc_lon_m_loan_card_detail,   
   sc_lon_m_ucf_loan_card_item  
WHERE ( sc_lon_m_loan_card_detail.item_type_code = sc_lon_m_ucf_loan_card_item.item_type_code ) 
--and sc_lon_m_loan_card_detail.loan_contract_no = 'conno'
--and  sc_lon_m_loan_card_detail.operate_date >= 'dd/mm/yyyy'
 
ORDER BY sc_lon_m_loan_card_detail.seq_no;

